import Axios from '@api/Axios';

const StaffAPI = {
    add: async(data) => await Axios.post('staffs', data),
    get: async(id) => await Axios.get(`staffs/${id}`),
    getAll: async() => await Axios.get(`staffs`),
    update: async(id, data) => await Axios.put(`staffs/${id}`, data),
    remove: async(id) =>  await Axios.delete(`staffs/${id}`),
}

export default StaffAPI;