import socketIOClient from 'socket.io-client';
import config from '@config';

import BillSocket from './Bill';
import CompanySocket from './Company';

class Socket {
    socket;

    constructor() {
        this.socket = socketIOClient(config.IO_URL);
    }

    Bill() {
        return new BillSocket(this.socket);
    }

    Company() {
        return new CompanySocket(this.socket);
    }
}

export default Socket;