import React, {useEffect, useState} from 'react';
import {Link} from 'react-router-dom';
import API from "@api";
import { BsList } from 'react-icons/bs';

import "./styles.scss";

import {sidebarItems} from './items';

export const SideBar = () => {
    const [location, setLocation] = useState(window.location.pathname);
    const [userPermission, setUserPermission] = useState(null);
    const [minimize, setMinimize] = useState(true);
    const [companySlug, setCompanySlug] = useState('');

    useEffect(() => {
        API.Permission.getUserPerm().then(res => {
            setUserPermission(res.data);
        });

        API.User.verifyToken().then(res => {
            setCompanySlug(res.data.company_slug);
        });
    }, []);

    const handleToggleSideBar = () => {
        localStorage.setItem("sidebar_minized", !minimize);
        setMinimize(!minimize);
    }
    
    const perms = userPermission?.perms;

    if(!perms) return null;

    return(
    <div className={`side_bar_container ${minimize ? 'min' : ''}`}>
        <div className={`side_bar`}>
            <div className='item avatar_container'>
                <button className="menu_btn" onClick={handleToggleSideBar}><BsList className="icon"/></button>
                <p className='user_name'>{localStorage.getItem('ho_ten')}</p>
            </div>

            {
                sidebarItems.map((item, index) => {
                    let permCheck = 0;

                    if(item.perms?.length) {
                        item.perms.map((perm) => {
                            if(permCheck >= 0) {
                                let key = Object.keys(perm)[0];
                                let permIndex = Object.values(perm)[0];
                                
                                if(perms[key][permIndex]) {
                                    permCheck++;
                                }else{
                                    permCheck = -1;
                                }
                            }
                        });
                    }else{
                        permCheck ++;
                    }

                    if(item.isDivider) return <br/>

                    if(permCheck > 0) {
                        if(item.isHeader) {
                            return (
                                <div className="menu_header" key={`sidebar-item-${index}`}>
                                    {
                                        minimize ? 
                                        <hr/> : <span>{item.name}</span>
                                    }
                                </div>
                            )
                        }
                        return (
                            <Link 
                                to={`/${companySlug}${item.path}`}
                                key={`sidebar-item-${index}`} 
                                className={location === `/${companySlug}${item.path}` ? 'item active' : 'item'} 
                                onClick={() => {
                                    setMinimize(true);
                                    setLocation(`/${companySlug}${item.path}`);
                                }}
                            >
                                <div className="icon">{item.icon}</div>
                                <p className="item_name">{item.name}</p>
                            </Link>
                        )
                    }
                })
            }
        </div>
    </div>
    )
}