class BillSocket {
    constructor(socket) {
        this.socket = socket;
    }
    
    //*EMITS
    emitAdd(data) {
        return this.socket.emit(`/client/bills/add`, data);
    }
    
    emitUpdate(data) {
        return this.socket.emit('/client/bills/update', data);
    }
    
    emitRemove(id) {
        return this.socket.emit(`/client/bills/remove`, {id});
    }

    //*LISTENERS
    onAdd(callback) {
        this.socket.on(`/server/bills/add`, callback);
    }

    onUpdate(callback) {
        this.socket.on(`/server/bills/update`, callback);
    }

    onRemove(callback) {
        this.socket.on(`/server/bills/remove`, callback);
    }
}

export default BillSocket;