import React, {Component} from 'react';
import {getBill} from '@functions/Api';
import {DefaultHeaderBar} from '@components/Header_bar';
import {HashSpiner} from '@components/Spiners';
import {removeVietnameseTones} from '@functions/Global';
import { Table } from '@components';
import API from '@api';

const TABLE_COLUMNS = [
    {
        key: "ten_chi_nhanh",
        title: "Chi nhánh",
    }, {
        key: "ten_khach_hang",
        title: "Tên khách hàng",
    }, {
        key: "so_dien_thoai",
        title: "Số điện thoại",
    }, {
        key: "dia_chi",
        title: "Địa chỉ",
    }
]

class CustomerScreen extends Component {
    constructor(props) {
        super(props);

        this.state = {
            bill: null
        }

        API.Bill.getAll().then(res => {
            let data = res.data.map((data) => {
                if(!data.deleted) {
                    return {
                        ten_chi_nhanh: data.chi_nhanh.ten_chi_nhanh,
                        ten_khach_hang: data.ten_khach_hang,
                        so_dien_thoai: data.so_dien_thoai,
                        dia_chi: data.dia_chi,
                    }
                }
            });

            this.setState ({
              bill: data
            })
        }).catch(e => console.log(e));
    }

    //THỰC HIỆN SEARCH
    handleSearch = (search_value) => {
        //RELOAD DATA IF SEARCH VALUE IS NULL
        if(search_value === "") {
            API.Bill.getAll().then(res => {
                let data = res.data.filter((data) => {
                    if(!data.deleted) {
                        return {
                            ten_chi_nhanh: data.chi_nhanh.ten_chi_nhanh,
                            ten_khach_hang: data.ten_khach_hang,
                            so_dien_thoai: data.so_dien_thoai,
                            dia_chi: data.dia_chi,
                        }
                    }
                })

                this.setState({
                    bill: data
                })     
            }).catch(e => console.log(e));
        }

        //RELOAD DATA
        API.Bill.getAll().then((res) => {
            //TÌM KHÁCH HÀNG OR TÊN BÉ OR SÔS ĐIỆN THOẠI
            let filtered_data = res.data.filter((data, i) => {
                const searchValue = removeVietnameseTones(search_value.toLowerCase());
                const tenKhachHang = removeVietnameseTones(data.ten_khach_hang.toLowerCase());
                const soDienThoai = data.so_dien_thoai;

                if((tenKhachHang.indexOf(searchValue) || soDienThoai.indexOf(searchValue)) && !data.deleted) {
                    return {
                        ten_chi_nhanh: data.chi_nhanh.ten_chi_nhanh,
                        ten_khach_hang: data.ten_khach_hang,
                        so_dien_thoai: data.so_dien_thoai,
                        dia_chi: data.dia_chi,
                    }
                }

                return false;
            })
  
            this.setState({
                bill: filtered_data
            })            
        }).catch(e => console.log(e));
    }

    render() {
        if(!this.state.bill) {
            return(<div className="load_view"><HashSpiner/></div>)
        }

        return(
            <div>
                <DefaultHeaderBar handleEdit={null} onSearchKeyPress={this.handleSearch} handleCreate={null} create_btn_link={null} handleSave={null} handleRemove={null} title="Khách Hàng"/>
                <Table
                    columns={TABLE_COLUMNS}
                    data={this.state.bill}
                />
            </div>
        )
    }
}

export default CustomerScreen;