import Axios from '@api/Axios';

const SpendingAPI = {
    add: async(data) => await Axios.post('spendings', data),
    get: async(id) => await Axios.get(`spendings/${id}`),
    getAll: async() => await Axios.get(`spendings`),
    update: async(id, data) => await Axios.put(`spendings/${id}`, data),
    remove: async(id) =>  await Axios.delete(`spendings/${id}`),
}

export default SpendingAPI;