import React, {Component} from 'react';
import {SpendingTable} from '@components/Table';
import {DefaultHeaderBar} from '@components/Header_bar';
import {getSingleSpending, getSpending, getPermissions} from '@functions/Api';
import {removeVietnameseTones, findWithAttr} from '@functions/Global';
import {HashSpiner} from '@components/Spiners';
import { Table, FormModal } from "@components";

import API from "@api";

const TABLE_COLUMNS = [
    {
        key: "date",
        title: "Ngày chi",
    }, {
        key: "noi_dung",
        title: "Nội dung",
    }, {
        key: "so_tien",
        title: "Số tiền",
    }, {
        key: "type",
        title: "Trạng thái thanh toán",
    }, {
        key: "nguoi_chi",
        title: "Người chi",
    }
]

class SpendingScreen extends Component {
    constructor(props) {
        super(props);
        this.state =  {
            modal_is_open: "false",
            edit_id: null,
            data_spending: null,
            perms: null
        }

        API.Permission.getUserPerm().then(res => {
            this.setState({
                perms: res.data.perms
            })
        }).catch(e => console.log(e));

        this.updateData();
    }

    handleCloseModal = () => {
        this.refs.noi_dung.value = "";
        this.refs.so_tien.value = "";

        this.setState({
            modal_is_open: "false",
            edit_modal_is_open: "false",
            data: null
        })

        this.updateData();
    }

    handleOpenModal = () => {
        this.setState({
            modal_is_open: "true"
        })
    }

    handleOpenEditModal = (id) => {
        API.Spending.get(id).then(res => {
            this.refs.noi_dung.value = res.data.noi_dung;
            this.refs.so_tien.value = res.data.so_tien;
            this.refs.type.value = res.data.type;

            this.setState({
                modal_is_open: "true",
                edit_id: id,
            })
        }).catch(e => console.log(e));
    }

    //THỰC HIỆN SEARCH
    handleSearch = (search_value) => {
        //RELOAD DATA IF SEARCH VALUE IS NULL
        if(search_value === "") {
            getSpending((res) => {
                this.setState({
                    data_spending: res.reverse()
                })            
            })
        }

        //RELOAD DATA
        getSpending((res) => {
            let data = res.reverse()
  
            //TÌM NGƯỜI CHI OR SỐ TIỀN HOẶC NỘI DUNG
            let filtered_data = data.filter((data, i) => {
                if(removeVietnameseTones(data.noi_dung).toLowerCase().indexOf(removeVietnameseTones(search_value).toLowerCase()) > -1) return true; 
                if(removeVietnameseTones(data.so_tien.toString()).toLowerCase().indexOf(removeVietnameseTones(search_value).toLowerCase()) > -1) return true;  
                if(removeVietnameseTones(data.user).toLowerCase().indexOf(removeVietnameseTones(search_value).toLowerCase()) > -1) return true;   
                
                return false;
            })
  
            this.setState({
                data_spending: filtered_data
            })            
        })
    }

    updateData = () => {
        API.Spending.getAll().then(res => {
            let data = res.data.map((item) => {
                return {
                    ...item,
                    nguoi_chi: item.user_id.ho_ten,
                    type: item.type == 1 ? "Chuyển khoản" : "Tiền mặt",
                    date: item.date_created.split("T")[0]
                }
            });

            this.setState({
                data_spending: data
            })
        }).catch(e => console.log(e));
    }

    handleSave = () => {
        if(this.refs.type.value == "2") {
            alert("Vui lòng chọn loại");
        }else{
            let data = {
                noi_dung: this.refs.noi_dung.value,
                so_tien: this.refs.so_tien.value,
                user_id: localStorage.getItem('user_id'),
                type: this.refs.type.value
            }

            if(this.state.edit_id) { //*Update
                API.Spending.update(this.state.edit_id, data).then(res => {
                    this.handleCloseModal();
                }).catch(e => console.log(e));
            }else{ //*Create
                API.Spending.add(data).then(res => {
                    this.handleCloseModal();
                }).catch(e => console.log(e));
            }
        }
    }

    handleRemove = () => {
        API.Spending.remove(this.state.edit_id).then(res => {
            this.handleCloseModal();
        }).catch(e => console.log(e));
    }

    render() {
        if(!this.state.data_spending || !this.state.perms) {
            return(<div className="load_view"><HashSpiner/></div>)
        }

        return(
            <div>
                <DefaultHeaderBar 
                    title="Chi" 
                    handleCreate={this.state.perms.spending[1] == "1" ? this.handleOpenModal : null} 
                    onSearchKeyPress={this.handleSearch}
                />

                <Table
                    columns={TABLE_COLUMNS}
                    data={this.state.data_spending}
                    onClick={this.handleOpenEditModal}
                />

                <FormModal 
                    title="Thêm Mục Đã Chi"
                    is_open={this.state.modal_is_open} 
                    onClose={
                        !this.state.edit_id ? 
                        () => this.setState({modal_is_open: "false"}) : null
                    }
                    onSave={
                        this.state.perms.spending[2] == "1" ?
                        () => this.handleSave() : null
                    }
                    onRemove={
                        this.state.perms.spending[3] == "1" && this.state.edit_id ?
                        () => this.handleRemove() : null
                    }
                >
                    <div className="box">
                        <span className="title">Nội dung chi</span>
                        <input type="text" className="textbox" ref="noi_dung"/>
                    </div>
                    <div className="box">
                        <span className="title">Số tiền đã chi</span>
                        <input type="number" className="textbox" ref="so_tien"/>
                    </div>
                    <div className="box">
                        <span className="title">Loại</span>
                        <select className="textbox"  ref="type" defaultValue="2">
                            <option value="2" disabled></option>
                            <option value="0">Chuyển Khoản</option>
                            <option value="1">Tiền Mặt</option>
                        </select>
                    </div>
                </FormModal> 
            </div>
        )
    }
}

export default SpendingScreen;