import CONFIG, {generateApiHeader} from "@config";
import axios from 'axios';
import Axios from '@api/Axios';

const SubscriptionAPI = {
    subscribe: async (id) => {
        const response = await axios.post(`${CONFIG.API}/subscriptions/subscribe/${id}`,{}, {
            headers: generateApiHeader()
        });
        
        return response.data;
    },
    createTransaction: async(id) => Axios.post(`subscriptions/create_transaction`, {
        subscription: id
    }),
    getCompany: async() => {
        const response = await axios.get(`${CONFIG.API}/subscriptions/get_company`,{
            headers: generateApiHeader()
        });
        
        return response.data;
    },
    getAll: async() => {
        const response = await axios.get(`${CONFIG.API}/subscriptions`,{
            headers: generateApiHeader()
        });
        
        return response.data;
    }
}

export default SubscriptionAPI;