import React, { useEffect } from 'react';

export const CloseTransactionScreen = ({}) => {
    useEffect(() => {
        window.close();
    }, []);

    return (
        <div>
            <h1>Close Transaction</h1>
        </div>
    )
}

export const TransactionSuccessScreen = () => {
    const handleClose = () => {
        window.close();
    }

    return (
        <div>
            <h1>Giao dịch thành công, hãy tải lại website để cập nhật gói mới nhé!</h1>
            <button onClick={handleClose}>Đóng</button>
        </div>
    )
}