import { NotificationManager } from "react-notifications";
import CONFIG from "@config";

const ERRS = CONFIG.HTTP_ERRORS;

class Alert {
    static _successTimeOut = 2000;

    static success(message) {
        NotificationManager.success(message, "Thành công", this._successTimeOut);
    }

    static error(message) {
        NotificationManager.error(ERRS[message] || message, "Lỗi", this._successTimeOut);
    }
}

export default Alert;