import CONFIG, {generateApiHeader} from "@config";
import axios from 'axios';

const UserAPI = {
    auth: async (email, password) => {
        const response = await axios.post(`${CONFIG.API}/staffs/auth`,{
            email: email,
            password: password
        }, {
            headers: generateApiHeader()
        });
        
        return response.data;
    },
    verifyToken: async() => {
        const response = await axios.get(`${CONFIG.API}/staffs/verify_token`, {
            headers: generateApiHeader()
        }).then(res => {
            let data = res.data.data;
            localStorage.setItem("chuc_vu", data.perm);
            localStorage.setItem("ho_ten", data.ho_ten);
            localStorage.setItem("email", data.email);
            localStorage.setItem("user_id", data._id);
            localStorage.setItem("company_id", data.company_id);
            localStorage.setItem("logged_time", new Date().toISOString());
            localStorage.setItem("authed", true);
            localStorage.setItem('ten_chuc_vu', "");
            localStorage.setItem(`${data.company_slug}_JWT`, data.accessToken);

            return res;
        }).catch(e => {
            if(localStorage.getItem("JWT")) {
                localStorage.clear();
                window.location.reload();
            }
        });
        
        return response?.data;
    }
}

export default UserAPI;