import React, {Component, useEffect} from 'react';
import {DefaultHeaderBar} from '@components/Header_bar';
import { BillForm, ProductListForm, ProductListTable, FormModal } from '@components';
import {Redirect} from 'react-router-dom';

import API from '@api';

import "@styles/views/Bill_Edit.scss";

class BillEditScreen extends Component {
    constructor(props) {
        super(props);
        this.state = {
           bill_data : null,
           product_data: [],
           products: {"products": []},
           product_total: 0,
           edit_data: null,
           data: null,
           is_modal_open: "false",
           is_edit_modal_open: "false",
           redirect: false,
           perms: null,
           date: this.props.match.params.date,
           print_bill: false,
           user_edited_name: null,
           is_editting: false,
           editing_id: null,
           packages: null
        }

        if(this.props.match.params.id !== "create_new") { //*EDIT
            API.Bill.get(this.props.match.params.id).then(res => {
                let billData = res.data;

                this.setState ({
                    data: billData,
                    user_edited_name: `Được chỉnh sửa bởi ${billData.user_id.ho_ten}`,
                    products: {"products": billData.products},
                    product_total: billData.tong,
                    editing_id: this.props.match.params.id,
                    is_editting: billData.deleted ? false : true
                })
            }).catch(e => console.log(e));
        }

        API.Permission.getUserPerm().then(res => {
            this.setState ({
                perms: res.data.perms
            })
        }).catch(e => console.log(e));

        this.fetchPackages();
    }

    fetchPackages = async() => {
        let packages = [];

        await API.PackageType.getSlug("goi_chup").then(res => {
            let typeId = res.data._id;

            API.Package.getType(typeId).then(res => {
                packages = res.data;
            });
        }).catch(e => console.log(e));

        await API.PackageType.getSlug("dich_vu").then(res => {
            let typeId = res.data._id;

            API.Package.getType(typeId).then(res => {
                packages = [...packages, ...res.data];

                this.setState ({
                    packages
                });
            });
        }).catch(e => console.log(e));
    }

    //*BILL
    //#region
    handleSaveOnclick = async () => {
        await this.refs.product_list_form.handleSave();
        await this.refs.bill_form.handleSave();
    }

    handleSave = async (data) => {
        this.setState ({
            bill_data: data
        })

        this.handleSubmit();
    }

    handleSubmit = () => {
        let data = Object.assign(this.state.bill_data,this.state.product_data, this.state.products);

        if(this.props.match.params.id !== "create_new" || this.state.is_editting) {
            data["date_created"] = this.state.data.date_created;

            API.Bill.update(this.state.editing_id, data).then(res => {
            }).catch(e => console.log(e));
        }else {
            API.Bill.add(data).then(res => {
                this.setState({
                    is_editting: true,
                    data: res.data,
                    products: {"products": res.data.products},
                    product_total: res.data.tong,
                    editing_id: res.data._id
                })
            }).catch(e => console.log(e));
        }
    }

    handleRemove = () => {
        if(this.state.bill_data?.deleted) {
            API.Bill.remove(this.props.match.params.id).then(res => {
    
                this.setState({
                    redirect: true
                })
            }).catch(e => console.log(e));
        }else{
            API.Bill.update(this.props.match.params.id, {deleted: true}).then(res => {
    
                this.setState({
                    redirect: true
                })
            }).catch(e => console.log(e));
        }
    }

    handlePrintBill = () => {
        this.setState({
            print_bill: true
        })
    }

    handleRestore = () => {
        API.Bill.update(this.props.match.params.id, {deleted: false}).then(res => {
            this.setState({
                redirect: true
            })
        }).catch(e => console.log(e));
    }
    //#endregion

    //*PRODUCT LIST
    //#region
    handleOpenAddProductModal = () => {
        this.setState ({
            is_modal_open: "true"
        })
    }

    handleOpenEditProductModal = (id) => {
        let data = {...this.state.products.products};
        data[id]["id"] = id;
        data = data[id];

        this.refs.giam_gia_san_pham.value = data.giam_gia || "";
        this.refs.ten_san_pham.value = data._id;
        this.refs.so_luong_san_pham.value = data.so_luong;

        this.setState ({
            is_modal_open: "true",
            edit_id: id,
        })
    }

    handleClearProductForm = () => {
        this.refs.so_luong_san_pham.value = "";
        this.refs.giam_gia_san_pham.value = "";
    }

    handleSaveProduct = () => {
        let data = this.state.packages.filter((data, i) => {
            return data._id == this.refs.ten_san_pham.value
        });

        let giam_gia = parseInt(this.refs.giam_gia_san_pham.value.toString().replace(/\.|\,/g,''))

        let product_data = {
            chiet_khau: 0,
            so_luong: this.refs.so_luong_san_pham.value,
            _id: data[0]._id,
            ten_goi: data[0].ten_goi,
            giam_gia: giam_gia,
            gia: data[0].gia
        }

        if(this.state.edit_id != null && this.state.edit_id >= 0) { //*EDIT
            let new_data = this.state.products.products;
    
            //THAY ĐỔI GIÁ TRỊ INPUT CÒN NỢ
            this.refs.product_list_form.handleUpdateConNoAfterChangeProduct(new_data[this.state.edit_id], product_data);
    
            let total = 0;
            new_data[this.state.edit_id] = product_data;

            new_data.map((data, i) => {
                total += (parseInt(data.gia) * parseInt(data.so_luong) * ((100 - parseInt(data.chiet_khau))/100) - parseInt(data.giam_gia ? data.giam_gia : 0));
            });
    
            this.setState({
                products: {"products": new_data},
                product_total: total,
                edit_id: null,
                is_modal_open: "false"
            })
        }else{//*CREATE
            let new_data = this.state.products;
            let total = 0;
            new_data.products.push(product_data);
    
            new_data.products.map((data, i) => {
                total += (parseInt(data.gia) * parseInt(data.so_luong) * ((100 - parseInt(data.chiet_khau))/100)) - (data.giam_gia ? parseInt(data.giam_gia) : 0);
            });
    
            this.setState({
                products: new_data,
                product_total: total,
                is_modal_open: "false"
            })
    
            this.refs.product_list_form.handleUpdateConNo(product_data);
        }
        this.handleClearProductForm();
    }

    handleRemoveProduct = () => {
        let data = this.state.products.products.filter((data, i) => {return i !== this.state.edit_id});
        let data_2 = this.state.products.products[this.state.edit_id];
        data_2["gia"] = parseInt('-' +  data_2["gia"]);

        //THAY ĐỔI GIÁ TRỊ INPUT CÒN NỢ
        this.refs.product_list_form.handleUpdateConNo(data_2);
        
        let total = 0;

        data.map((data, i) => {
            total += parseInt(data.gia) * parseInt(data.so_luong) * ((100 - parseInt(data.chiet_khau))/100);
        })

        this.setState({
            products: {"products": data},
            product_total: total,
            is_modal_open: "false"
        })
    }

    handleSavePayment = (data) => {
        this.setState({
            product_data: data
        })
    }
    //#endregion

    render() {
        if(!this.state.data && this.props.match.params.id !== "create_new" || !this.state.perms || !this.state.packages) {
            return(<div></div>)
        }

        if(this.state.redirect) {
            if(window.location.pathname.split('/')[1] === "bill_restore") {
                return <Redirect to="/trash"/>
            }
            return <Redirect to="/"/>
        }

        if(this.state.print_bill) {
            return <Redirect to={`/bill_print/${this.state.editing_id}`}/>
        }
 
        return(
            <div className="bill_edit_view">
                {!this.state.is_editting ? this.props.match.params.id == "create_new" ? 
                    <DefaultHeaderBar 
                        customTitle={this.state.user_edited_name}  
                        onGoBack={() => this.props.history.goBack()} 
                        title="Đơn Hàng" 
                        back_link="/" 
                        handleSave={this.state.perms.bill[1] == "1" ? this.handleSaveOnclick : null} 
                        handleAddProduct={this.handleOpenAddProductModal}
                    /> : 
                    <DefaultHeaderBar 
                        customTitle={this.state.user_edited_name} 
                        onGoBack={() => this.props.history.goBack()} 
                        handleRestore={this.state.perms.trash[2] == "1" ? this.handleRestore : null} 
                        handleRemove={this.state.perms.trash[3] == "1" ? this.handleRemove : null} 
                        title="Thùng Rác" 
                        back_link="/"
                    /> : 
                    <DefaultHeaderBar 
                        customTitle={this.state.user_edited_name} 
                        handlePrintBill={this.handlePrintBill}  
                        onGoBack={() => this.props.history.goBack()} 
                        handleRemove={this.state.perms.bill[3] == "1" ? this.handleRemove : null} 
                        title="Đơn Hàng" 
                        back_link="/" 
                        handleSave={this.handleSaveOnclick} 
                        handleAddProduct={this.handleOpenAddProductModal}
                    />
                }
                <BillForm date={this.state.date} perms={this.state.perms} ref="bill_form" onSave={this.handleSave} data={this.state.data}/>
                
                <h1 className="view_header" style={{marginTop: "64px", marginLeft: "16px"}}>Danh Sách Sản Phẩm</h1>
    
                <div className="product_list_container" style={{display: "fles"}}>
                    <ProductListTable data={this.state.products.products} onEdit={this.handleOpenEditProductModal}/>
                    <ProductListForm perms={this.state.perms}  ref="product_list_form" data={this.state.data} product_total={this.state.product_total} handleSavePayment={this.handleSavePayment} onSave={this.handleSaveProduct}/>
                </div>

                <FormModal 
                    title="Sản Phẩm"
                    is_open={this.state.is_modal_open} 
                    onClose={
                        !(this.state.edit_id != null && this.state.edit_id >= 0) ? 
                        () => this.setState({is_modal_open: "false"}) : null
                    }
                    onSave={
                        this.state.perms.bill[2] == "1" ?
                        () => this.handleSaveProduct() : null
                    }
                    onRemove={
                        this.state.perms.bill[3] == "1" && (this.state.edit_id != null && this.state.edit_id >= 0) ?
                        () => this.handleRemoveProduct() : null
                    }
                >
                    <div className="box" style={{width: "215px"}}>
                       <span className="title">Tên sản phẩm</span>
                       <select 
                            ref="ten_san_pham"
                            disabled={this.state.perms.bill[2] != "1"}
                        >
                           {this.state.packages.map((data, i) => {
                               return <option value={data._id} key={`product-list-item-${i}`}>{data.ten_goi}</option>  
                           })}
                       </select>
                    </div>

                     <div className="box">
                         <span className="title">Số lượng</span>
                         <input type="number" min="0" className="textbox" ref="so_luong_san_pham" disabled={this.state.perms.bill[2] != "1"}/>
                     </div>

                    <div className="box">
                        <span className="title">Giảm giá</span>
                        <input type="number" className="textbox" ref="giam_gia_san_pham" min="0"/>
                    </div>
                </FormModal> 
            </div>
        )
    }
}   

export default BillEditScreen;